  it.todo("should kill two live cells that each have only one neighbor (underpopulation)");
  it.todo("should keep alive a live cell with three neighbors (survival)");
  it.todo("should kill a live cell with four neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly three neighbors to life (reproduction)");
